package main

import (
	"sync"

	"github.com/robertkrimen/otto"
)

// FilterItems filters a slice of map[string]interface{} items using a JavaScript condition script.
// The script is evaluated once per item, with the current item exposed as the global variable 'item'.
// The script should evaluate to a truthy or falsy value; items for which the script is truthy are included in the result.
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	var result []map[string]interface{}
	var mu sync.Mutex // Protect concurrent access to result slice
	var wg sync.WaitGroup
	errChan := make(chan error, len(items))

	// Pre-compile the script once for performance
	vm := otto.New()
	compiledScript, err := vm.Compile("", conditionScript)
	if err != nil {
		return nil, err
	}

	for _, item := range items {
		wg.Add(1)
		go func(currentItem map[string]interface{}) {
			defer wg.Done()

			// Create a new VM for each goroutine to isolate execution contexts
			vm := otto.New()

			// Set a stack depth limit to prevent DoS attacks
			vm.SetStackDepthLimit(32)

			// Inject the current item as a global variable named 'item'
			err := vm.Set("item", currentItem)
			if err != nil {
				errChan <- err
				return
			}

			// Run the pre-compiled script
			value, err := vm.Run(compiledScript)
			if err != nil {
				errChan <- err
				return
			}

			// Convert result to boolean using JavaScript truthiness
			boolResult, err := value.ToBoolean()
			if err != nil {
				errChan <- err
				return
			}

			if boolResult {
				mu.Lock()
				result = append(result, currentItem)
				mu.Unlock()
			}
		}(item)
	}

	wg.Wait()
	close(errChan)

	// Check for any errors
	for err := range errChan {
		if err != nil {
			return nil, err
		}
	}

	return result, nil
}

