// FilterItems filters a slice of items based on a JavaScript condition script.
// It injects each item as a global variable named 'item' in the JavaScript environment
// and evaluates the condition script. Items for which the script evaluates to true
// are included in the returned slice.
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	// Create a new Otto VM for script execution
	vm := otto.New()

	// Pre-compile the condition script for better performance
	script, err := vm.Compile("", conditionScript)
	if err != nil {
		return nil, fmt.Errorf("failed to compile condition script: %w", err)
	}

	// Result slice for filtered items
	filteredItems := make([]map[string]interface{}, 0, len(items))

	// Iterate through each item and evaluate the condition
	for _, item := range items {
		// Set the current item as a global variable in the VM
		if err := vm.Set("item", item); err != nil {
			return nil, fmt.Errorf("failed to set item variable: %w", err)
		}

		// Execute the condition script
		value, err := vm.Run(script)
		if err != nil {
			return nil, fmt.Errorf("failed to execute condition script: %w", err)
		}

		// Convert the result to boolean
		conditionResult, err := value.ToBoolean()
		if err != nil {
			return nil, fmt.Errorf("condition script must evaluate to boolean: %w", err)
		}

		// If condition is true, include the item in the result
		if conditionResult {
			filteredItems = append(filteredItems, item)
		}
	}

	return filteredItems, nil
}

