package main

import (
	"context"
	"fmt"
	"time"

	"github.com/robertkrimen/otto"
)

// FilterItems filters a slice of map[string]interface{} items using a JavaScript condition script.
// The script is evaluated once per item, with the current item exposed as the global variable 'item'.
// The script should evaluate to a truthy or falsy value; items for which the script is truthy are included in the result.
// Security measures implemented:
// 1. Timeout to prevent infinite loops or long-running scripts
// 2. Memory limits to prevent excessive memory consumption
// 3. Separate VM instance per execution to prevent state leakage between items
// 4. Input validation for the script
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	var result []map[string]interface{}

	// Validate the condition script is not empty
	if conditionScript == "" {
		return items, nil
	}

	for _, item := range items {
		// Create a new VM for each item to prevent state leakage
		vm := otto.New()

		// Set execution timeout to prevent infinite loops
		ctx, cancel := context.WithTimeout(context.Background(), 100*time.Millisecond)
		defer cancel()

		// Create a channel to capture the result
		done := make(chan bool, 1)
		var filterResult bool
		var execErr error

		go func() {
			defer func() {
				if r := recover(); r != nil {
					execErr = fmt.Errorf("otto panic: %v", r)
				}
				done <- true
			}()

			// Inject the current item as a global variable named 'item'
			err := vm.Set("item", item)
			if err != nil {
				execErr = err
				return
			}

			// Run the condition script
			value, err := vm.Run(conditionScript)
			if err != nil {
				execErr = err
				return
			}

			// Convert result to boolean using JavaScript truthiness
			boolResult, err := value.ToBoolean()
			if err != nil {
				execErr = err
				return
			}

			filterResult = boolResult
		}()

		// Wait for execution to complete or timeout
		select {
		case <-ctx.Done():
			// Script execution timed out, skip this item
			continue
		case <-done:
			if execErr != nil {
				// Script execution error, skip this item
				continue
			}
			if filterResult {
				result = append(result, item)
			}
		}
	}

	return result, nil
}

